def is_balanced(s):
    stack = []
    bracket_map = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.append(char)
        elif char in ')]}':
            if not stack or stack[-1] != bracket_map[char]:
                return False
            stack.pop()
    return len(stack) == 0

# Run all test cases
tests = [
    ('()[]{}', True),
    ('([{}])', True),
    ('([)]', False),
    ('{[}', False),
    ('', True),
]

for s, expected in tests:
    result = is_balanced(s)
    status = '✓' if result == expected else '✗'
    print(f'{status} is_balanced(\"{s}\") → {result}')
"
